        </svg>
    };

    const universeLink = {
        path: '/universe',
        label: 'Universe',
        action: () => navigate('/universe'),
        icon:
        <svg xmlns="http://www.w3.org/2000/svg" width="28px" height="28px" viewBox="0 0 24 24" fill={location.pathname === '/universe' ? "#5f92ff" : "#b6b6b6"}>
            <circle cx="6" cy="6" r="2"/>
