 88→export const respondConstellationService = async (userId, constellationId, accept) => {
 89→    if (!userId || !constellationId) {
 90→        throw { status: 400, error: 'userId and constellationId are required' };
 91→    }
 92→
 93→    const { data: constellation, error: errorFetch } = await supabase
 94→        .from('constellations')
 95→        .select('*')
 96→        .eq('id', constellationId)
 97→        .maybeSingle();
 98→
 99→    if (errorFetch) {
100→        console.error('supabase error fetching constellation:', errorFetch.message);
101→        throw { status: 500, error: 'error fetching constellation' };
102→    }
103→    if (!constellation) {
104→        throw { status: 404, error: 'constellation not found' };
105→    }
106→    if (constellation.status !== 'pending') {
107→        throw { status: 400, error: 'constellation has already been responded to' };
108→    }
109→
110→    // The responder must be the user who did NOT initiate
111→    const isRecipient = constellation.user_id_a === userId || constellation.user_id_b === userId;
112→    if (!isRecipient) {
113→        throw { status: 403, error: 'you are not a participant of this constellation' };
114→    }
115→
116→    // Determine who the initiator was (the sender of the request notification)
117→    // The initiator is the one who is NOT the current user responding
118→    const initiatorId = constellation.user_id_a === userId ? constellation.user_id_b : constellation.user_id_a;
119→
120→    const newStatus = accept ? 'accepted' : 'declined';
121→
122→    const { error: errorUpdate } = await supabase
123→        .from('constellations')
124→        .update({ status: newStatus })
125→        .eq('id', constellationId);
126→
127→    if (errorUpdate) {
128→        console.error('supabase error updating constellation:', errorUpdate.message);
129→        throw { status: 500, error: 'error updating constellation status' };
130→    }
131→
132→    // If accepted, notify the initiator
133→    if (accept) {
134→        const { error: errorNotif } = await supabase
135→            .from('notifications')
136→            .insert({
137→                sender_id: userId,
138→                receiver_id: initiatorId,
139→                journal_id: constellation.star_id_a,
140→                type: 'constellation_accepted',
141→                constellation_id: constellationId,
142→                read: false,
143→            });
144→
145→        if (errorNotif) {
146→            console.error('supabase error inserting acceptance notification:', errorNotif.message);
147→        }
148→    }
149→
150→    return { message: accept ? 'constellation accepted' : 'constellation declined' };
151→};
