 11→const simpleHash = (str) => {
 12→    let h = 0;
 13→    for(let i = 0; i < str.length; i++){
 14→        h = ((h << 5) - h + str.charCodeAt(i)) | 0;
 15→    }
 16→    return h;
 17→};
 18→
 19→const userHomeCoords = (userId) => {
 20→    const mid = Math.floor(userId.length / 2);
 21→    const xHash = Math.abs(simpleHash(userId.slice(0, mid)));
 22→    const yHash = Math.abs(simpleHash(userId.slice(mid)));
 23→    const x = (xHash % 50001) / 50000 * 50000 - 25000;
 24→    const y = (yHash % 50001) / 50000 * 50000 - 25000;
 25→    return {x, y};
 26→};
 27→
 28→const spiralLayout = (index) => {
 29→    if(index === 0) return {dx: 0, dy: 0};
 30→    const angle = index * 0.8;
 31→    const radius = 30 * Math.sqrt(index);
 32→    return {dx: radius * Math.cos(angle), dy: radius * Math.sin(angle)};
 33→};
